import{A as e}from"./fpANyc4T.js";import{u as d}from"./fakKg52O.js";import{_ as o,c as s,a as t,d as r,a0 as n,b as c,o as l}from"./-HEJcDum.js";const v={class:"privacy-page min-h-screen bg-gradient-to-br from-gray-900 via-blue-900 to-gray-900 text-white"},p={class:"container mx-auto px-4 py-8 max-w-4xl"},u={name:"PrivacyPage",components:{AppFooter:e}},m=Object.assign(u,{setup(g){return d({title:"Privacy Policy - SwimPractices",meta:[{name:"description",content:"Privacy Policy for SwimPractices - Learn how we collect, use, and protect your personal information including Apple Sign-In, HealthKit data, and Firebase storage."},{name:"keywords",content:"privacy policy, data protection, HealthKit privacy, Apple Sign-In, Firebase security, swimming app privacy"}]}),(i,a)=>(l(),s("div",v,[t("div",p,[t("button",{onClick:a[0]||(a[0]=y=>i.$router.push("/")),class:"mb-6 flex items-center text-gray-300 hover:text-white transition-colors duration-200"},[...a[1]||(a[1]=[t("svg",{class:"w-5 h-5 mr-2",fill:"none",stroke:"currentColor",viewBox:"0 0 24 24"},[t("path",{"stroke-linecap":"round","stroke-linejoin":"round","stroke-width":"2",d:"M15 19l-7-7 7-7"})],-1),r(" Back to Home ",-1)])]),a[2]||(a[2]=n('<div class="text-center mb-12" data-v-a1ad3d01><h1 class="text-5xl font-bold mb-4" data-v-a1ad3d01>Privacy Policy</h1><p class="text-xl text-gray-300" data-v-a1ad3d01>Last Updated: November 19, 2025</p></div><div class="privacy-card mb-6" data-v-a1ad3d01><h2 class="section-title" data-v-a1ad3d01>Introduction</h2><p class="section-text" data-v-a1ad3d01> Welcome to SwimPractices. We are committed to protecting your privacy and ensuring the security of your personal information. This Privacy Policy explains how we collect, use, disclose, and safeguard your data when you use our mobile application and web platform (collectively, &quot;Services&quot;). </p><p class="section-text mt-4" data-v-a1ad3d01> By using SwimPractices, you agree to the collection and use of information in accordance with this policy. If you do not agree with our policies and practices, please do not use our Services. </p></div><div class="privacy-card mb-6" data-v-a1ad3d01><h2 class="section-title" data-v-a1ad3d01>Information We Collect</h2><h3 class="subsection-title" data-v-a1ad3d01>1. Apple Sign-In Data (iOS App)</h3><p class="section-text" data-v-a1ad3d01> When you sign in using Apple Sign-In on our iOS app, we collect: </p><ul class="privacy-list" data-v-a1ad3d01><li data-v-a1ad3d01><strong data-v-a1ad3d01>Email Address:</strong> Your email address or Apple&#39;s private relay email if you choose to hide your email</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Full Name:</strong> Your first and last name as provided by your Apple ID</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Apple User ID:</strong> A unique identifier provided by Apple to identify your account</li></ul><p class="section-text mt-4" data-v-a1ad3d01> We use this information solely for account creation, authentication, and to provide you with a personalized experience. </p><h3 class="subsection-title mt-6" data-v-a1ad3d01>2. Account Registration Data (Web App)</h3><p class="section-text" data-v-a1ad3d01> When you create an account on our web platform, we collect: </p><ul class="privacy-list" data-v-a1ad3d01><li data-v-a1ad3d01><strong data-v-a1ad3d01>Email Address:</strong> Used for account identification and password recovery</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Username:</strong> Your display name within the app</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>User ID:</strong> A unique identifier assigned to your account</li></ul><h3 class="subsection-title mt-6" data-v-a1ad3d01>3. HealthKit Data (iOS App)</h3><p class="section-text" data-v-a1ad3d01> With your explicit permission, our iOS app accesses HealthKit to retrieve swimming workout data, including: </p><ul class="privacy-list" data-v-a1ad3d01><li data-v-a1ad3d01><strong data-v-a1ad3d01>Swimming Workouts:</strong> Distance, duration, and stroke type</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Workout Metrics:</strong> Swimming performance data and fitness information</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Activity Data:</strong> General workout and activity information related to swimming</li></ul><p class="section-text mt-4" data-v-a1ad3d01><strong data-v-a1ad3d01>Important:</strong> HealthKit data is only accessed when you grant permission through iOS system prompts. This data is used exclusively to enhance your training experience and is never shared with third parties. You can revoke HealthKit permissions at any time through your device&#39;s Settings app. </p><h3 class="subsection-title mt-6" data-v-a1ad3d01>4. Swimming Practice &amp; Preference Data</h3><p class="section-text" data-v-a1ad3d01> To provide personalized swim practice recommendations, we collect and store: </p><ul class="privacy-list" data-v-a1ad3d01><li data-v-a1ad3d01><strong data-v-a1ad3d01>Swimming Intervals:</strong> Your pace preferences for different strokes (freestyle, backstroke, butterfly, breaststroke, individual medley)</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Pool Preferences:</strong> Your preferred pool length (25 yards, 25 meters, 50 meters)</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Practice History:</strong> Swim practices you&#39;ve created, completed, or saved</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Skill Level:</strong> Experience level to tailor workout difficulty</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Season Tracker Data:</strong> Optional training goals and progress metrics</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Pinned Practices:</strong> Practices you&#39;ve bookmarked for quick access</li></ul><h3 class="subsection-title mt-6" data-v-a1ad3d01>5. Usage Data &amp; Analytics</h3><p class="section-text" data-v-a1ad3d01> We automatically collect certain information when you use our Services: </p><ul class="privacy-list" data-v-a1ad3d01><li data-v-a1ad3d01><strong data-v-a1ad3d01>Device Information:</strong> Browser type, operating system, device model</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Usage Information:</strong> Pages viewed, features used, time spent in the app</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Performance Data:</strong> App crashes, errors, and performance metrics</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Location Data:</strong> Approximate geographic location based on IP address (web app only)</li></ul><p class="section-text mt-4" data-v-a1ad3d01> This data is collected through Google Analytics (Firebase) and is used to improve app performance and user experience. </p></div><div class="privacy-card mb-6" data-v-a1ad3d01><h2 class="section-title" data-v-a1ad3d01>How We Use Your Information</h2><p class="section-text" data-v-a1ad3d01>We use the collected information for the following purposes:</p><ul class="privacy-list" data-v-a1ad3d01><li data-v-a1ad3d01><strong data-v-a1ad3d01>Account Management:</strong> Create and manage your user account, authenticate your identity</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Personalized Experience:</strong> Generate customized swim practices based on your preferences, skill level, and goals</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>AI Practice Generation:</strong> Use your historical data and preferences to create intelligent, progressive workout plans</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Progress Tracking:</strong> Track your training progress, total distance, and season goals</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Leaderboard Features:</strong> Display your total swimming distance on community leaderboards (updated every 24 hours)</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Service Improvement:</strong> Analyze usage patterns to enhance features and user experience</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Communication:</strong> Send you important updates about your account or our Services</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Technical Support:</strong> Respond to your requests and provide customer support</li></ul></div><div class="privacy-card mb-6" data-v-a1ad3d01><h2 class="section-title" data-v-a1ad3d01>Data Storage &amp; Third-Party Services</h2><h3 class="subsection-title" data-v-a1ad3d01>Firebase / Google Cloud Platform</h3><p class="section-text" data-v-a1ad3d01> We use Firebase (a Google service) to store and manage your data. Your information is stored in Firebase&#39;s Cloud Firestore database, which is subject to Google&#39;s security standards and privacy practices. </p><ul class="privacy-list mt-4" data-v-a1ad3d01><li data-v-a1ad3d01><strong data-v-a1ad3d01>What we store:</strong> User profiles, practice data, preferences, authentication tokens, and analytics</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Location:</strong> Data is stored on Google Cloud servers, which may be located in various geographic regions</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Privacy Policy:</strong> <a href="https://firebase.google.com/support/privacy" target="_blank" rel="noopener noreferrer" class="privacy-link" data-v-a1ad3d01>https://firebase.google.com/support/privacy</a></li></ul><h3 class="subsection-title mt-6" data-v-a1ad3d01>Netlify Identity</h3><p class="section-text" data-v-a1ad3d01> Our web application uses Netlify Identity for user authentication and account management. </p><ul class="privacy-list mt-4" data-v-a1ad3d01><li data-v-a1ad3d01><strong data-v-a1ad3d01>What they receive:</strong> Email address, username, authentication metadata</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Privacy Policy:</strong> <a href="https://www.netlify.com/privacy/" target="_blank" rel="noopener noreferrer" class="privacy-link" data-v-a1ad3d01>https://www.netlify.com/privacy/</a></li></ul><h3 class="subsection-title mt-6" data-v-a1ad3d01>AI Practice Generation Service</h3><p class="section-text" data-v-a1ad3d01> To generate intelligent swim practices, we use an AI-powered service that receives: </p><ul class="privacy-list mt-4" data-v-a1ad3d01><li data-v-a1ad3d01>Your swimming preferences and interval settings</li><li data-v-a1ad3d01>Historical practice data and patterns</li><li data-v-a1ad3d01>Season progression information</li><li data-v-a1ad3d01>Distance and stroke preferences</li></ul><p class="section-text mt-4" data-v-a1ad3d01> This data is used solely to generate personalized workout plans and is not used for any other purpose. </p><h3 class="subsection-title mt-6" data-v-a1ad3d01>Google Analytics</h3><p class="section-text" data-v-a1ad3d01> We use Google Analytics to understand how users interact with our Services. Google Analytics collects standard web analytics data including page views, session duration, device information, and approximate geographic location. </p><ul class="privacy-list mt-4" data-v-a1ad3d01><li data-v-a1ad3d01><strong data-v-a1ad3d01>Privacy Policy:</strong> <a href="https://policies.google.com/privacy" target="_blank" rel="noopener noreferrer" class="privacy-link" data-v-a1ad3d01>https://policies.google.com/privacy</a></li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Opt-out:</strong> You can opt out of Google Analytics by installing the <a href="https://tools.google.com/dlpage/gaoptout" target="_blank" rel="noopener noreferrer" class="privacy-link" data-v-a1ad3d01>Google Analytics Opt-out Browser Add-on</a></li></ul><h3 class="subsection-title mt-6" data-v-a1ad3d01>Local Storage (Web App)</h3><p class="section-text" data-v-a1ad3d01> Our web application stores certain data in your browser&#39;s local storage to improve performance and reduce server requests: </p><ul class="privacy-list mt-4" data-v-a1ad3d01><li data-v-a1ad3d01>Cached practice data (refreshed every 50 minutes)</li><li data-v-a1ad3d01>Last fetch timestamps</li></ul><p class="section-text mt-4" data-v-a1ad3d01> This data remains on your device and can be cleared by clearing your browser&#39;s cache. </p></div><div class="privacy-card mb-6" data-v-a1ad3d01><h2 class="section-title" data-v-a1ad3d01>Data Sharing &amp; Disclosure</h2><p class="section-text" data-v-a1ad3d01> We do not sell, trade, or rent your personal information to third parties. We only share your data in the following limited circumstances: </p><ul class="privacy-list" data-v-a1ad3d01><li data-v-a1ad3d01><strong data-v-a1ad3d01>Service Providers:</strong> With trusted third-party services (Firebase, Netlify, Google Analytics) necessary to operate our Services</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Public Information:</strong> Your username and total swimming distance may be displayed on public leaderboards</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Legal Requirements:</strong> When required by law, court order, or governmental regulation</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Safety &amp; Protection:</strong> To protect the rights, property, or safety of SwimPractices, our users, or others</li></ul></div><div class="privacy-card mb-6" data-v-a1ad3d01><h2 class="section-title" data-v-a1ad3d01>Data Security</h2><p class="section-text" data-v-a1ad3d01> We implement industry-standard security measures to protect your personal information: </p><ul class="privacy-list" data-v-a1ad3d01><li data-v-a1ad3d01><strong data-v-a1ad3d01>Encryption:</strong> Data transmission is encrypted using HTTPS/TLS protocols</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Authentication:</strong> Secure authentication tokens with automatic expiration (1-hour lifetime)</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Access Controls:</strong> Cloud Functions validate user permissions to ensure you can only access your own data</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Data Separation:</strong> Public and private user data are stored in separate database collections</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Token Management:</strong> Authentication tokens are not stored in browser storage for enhanced security</li></ul><p class="section-text mt-4" data-v-a1ad3d01> However, no method of transmission over the internet or electronic storage is 100% secure. While we strive to protect your personal information, we cannot guarantee absolute security. </p></div><div class="privacy-card mb-6" data-v-a1ad3d01><h2 class="section-title" data-v-a1ad3d01>Your Privacy Rights</h2><p class="section-text" data-v-a1ad3d01>You have the following rights regarding your personal data:</p><ul class="privacy-list" data-v-a1ad3d01><li data-v-a1ad3d01><strong data-v-a1ad3d01>Access:</strong> Request a copy of the personal information we hold about you</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Correction:</strong> Update or correct your account information at any time</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Deletion:</strong> Request deletion of your account and associated data</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Portability:</strong> Request a copy of your data in a machine-readable format</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>HealthKit Control:</strong> Revoke HealthKit permissions through iOS Settings at any time</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Opt-out:</strong> Opt out of analytics tracking through browser settings or Google Analytics opt-out</li></ul><p class="section-text mt-4" data-v-a1ad3d01> To exercise any of these rights, please contact us using the information provided below. </p></div><div class="privacy-card mb-6" data-v-a1ad3d01><h2 class="section-title" data-v-a1ad3d01>Data Retention</h2><p class="section-text" data-v-a1ad3d01>We retain your personal information for the following periods:</p><ul class="privacy-list" data-v-a1ad3d01><li data-v-a1ad3d01><strong data-v-a1ad3d01>Account Data:</strong> Retained for the lifetime of your account unless you request deletion</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Practice History:</strong> Retained indefinitely to maintain your training records</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Daily Generated Practices:</strong> Cleared and regenerated every 24 hours</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Cached Browser Data:</strong> Automatically cleared after 50 minutes</li><li data-v-a1ad3d01><strong data-v-a1ad3d01>Analytics Data:</strong> Retained according to Google Analytics retention policies (14-50 months)</li></ul><p class="section-text mt-4" data-v-a1ad3d01> Upon account deletion, we will remove your personal information from our active databases within 30 days, though some data may remain in backups for a limited time. </p></div><div class="privacy-card mb-6" data-v-a1ad3d01><h2 class="section-title" data-v-a1ad3d01>Children&#39;s Privacy</h2><p class="section-text" data-v-a1ad3d01> SwimPractices is designed for swimmers of all ages, including minors. We comply with the Children&#39;s Online Privacy Protection Act (COPPA) and do not knowingly collect personal information from children under 13 without parental consent. </p><p class="section-text mt-4" data-v-a1ad3d01> If you are a parent or guardian and believe your child has provided us with personal information without your consent, please contact us immediately, and we will delete such information from our systems. </p></div><div class="privacy-card mb-6" data-v-a1ad3d01><h2 class="section-title" data-v-a1ad3d01>International Data Transfers</h2><p class="section-text" data-v-a1ad3d01> Your information may be transferred to, and maintained on, servers located outside of your state, province, country, or other governmental jurisdiction where data protection laws may differ. </p><p class="section-text mt-4" data-v-a1ad3d01> By using SwimPractices, you consent to the transfer of your information to the United States and other countries where our service providers operate. </p></div><div class="privacy-card mb-6" data-v-a1ad3d01><h2 class="section-title" data-v-a1ad3d01>California Privacy Rights (CCPA)</h2><p class="section-text" data-v-a1ad3d01> If you are a California resident, you have additional rights under the California Consumer Privacy Act (CCPA): </p><ul class="privacy-list" data-v-a1ad3d01><li data-v-a1ad3d01>Right to know what personal information is collected, used, shared, or sold</li><li data-v-a1ad3d01>Right to delete personal information held by businesses</li><li data-v-a1ad3d01>Right to opt-out of sale of personal information (Note: We do not sell personal information)</li><li data-v-a1ad3d01>Right to non-discrimination for exercising CCPA rights</li></ul><p class="section-text mt-4" data-v-a1ad3d01> To exercise these rights, please contact us using the information below. </p></div><div class="privacy-card mb-6" data-v-a1ad3d01><h2 class="section-title" data-v-a1ad3d01>Changes to This Privacy Policy</h2><p class="section-text" data-v-a1ad3d01> We may update this Privacy Policy from time to time to reflect changes in our practices or for legal, operational, or regulatory reasons. When we make changes, we will update the &quot;Last Updated&quot; date at the top of this policy. </p><p class="section-text mt-4" data-v-a1ad3d01> We encourage you to review this Privacy Policy periodically. Continued use of our Services after changes are posted constitutes your acceptance of the updated policy. </p></div><div class="privacy-card mb-6" data-v-a1ad3d01><h2 class="section-title" data-v-a1ad3d01>Contact Us</h2><p class="section-text" data-v-a1ad3d01> If you have any questions, concerns, or requests regarding this Privacy Policy or our data practices, please contact us: </p><div class="contact-box mt-4" data-v-a1ad3d01><p class="font-semibold" data-v-a1ad3d01>SwimPractices</p><p class="text-gray-300 mt-2" data-v-a1ad3d01>Email: <a href="mailto:privacy@swimpractices.com" class="privacy-link" data-v-a1ad3d01>privacy@swimpractices.com</a></p><p class="text-gray-300 mt-1" data-v-a1ad3d01>For privacy-related inquiries, we will respond within 30 days.</p></div></div><div class="privacy-card bg-blue-900/30 border-blue-500" data-v-a1ad3d01><h2 class="section-title" data-v-a1ad3d01>Summary</h2><p class="section-text" data-v-a1ad3d01> At SwimPractices, your privacy matters. We collect only the information necessary to provide you with an exceptional swimming training experience. Your data is secured, never sold, and you maintain control over your information at all times. </p><p class="section-text mt-4" data-v-a1ad3d01> Thank you for trusting SwimPractices with your swimming journey. </p></div>',15))]),c(e)]))}}),b=o(m,[["__scopeId","data-v-a1ad3d01"]]);export{b as default};
